mapper.select:
SELECT  
  FROM  TB_RSS A
 WHERE  A.RSS_ID = #{rssId}

mapper.insert:
INSERT  INTO TB_RSS
      ( RSS_ID
      , TRGET_SVC_NM
      , TRGET_SVC_TABLE
      , HDER_TITLE
      , HDER_LINK
      , FRST_REGIST_PNTTM
      , FRST_REGISTER_ID )
VALUES  ( #{rssId}
        , #{trgetSvcNm}
        , #{trgetSvcTable}
        , #{hderTitle}
        , #{hderLink}
        , CURRENT_TIMESTAMP
        , #{frstRegisterId} )

mapper.update:
UPDATE  TB_RSS
   SET  TRGET_SVC_NM    = #{trgetSvcNm}
      , HDER_TITLE      = #{hderTitle}
      , LAST_UPDT_PNTTM = CURRENT_TIMESTAMP
 WHERE  RSS_ID = #{rssId}
